    getTranslatedTypeName: function(type) {
        var map = {
            "Script Include": "Script de Servidor",
            "Business Rule": "Regra de Negócio",
            "UI Page": "Página de Interface",
            "UI Action": "Botão ou Ação de Interface",
            "UI Policy": "Política de Interface",
            "Client Script": "Script de Cliente",
            "Table": "Tabela de Dados",
            "Field Label": "Rótulo de Campo",
            "Flow": "Fluxo de Automação",
            "Subflow": "Subfluxo",
            "Widget": "Componente de Portal",
            "Catalog Item": "Item de Catálogo",
            "Record Producer": "Produtor de Registro",
            "Notification": "Notificação",
            "Report": "Relatório",
            "Dashboard": "Painel",
            "Role": "Função de Acesso",
            "Group": "Grupo de Usuários",
            "Property": "Propriedade do Sistema",
            "Scripted REST API": "API REST Personalizada",
            "Transform Map": "Mapa de Transformação",
            "Import Set Table": "Tabela de Importação",
            "Access Control": "Controle de Acesso",
            "Workflow": "Fluxo de Trabalho",
            "Application Menu": "Menu de Aplicação",
            "Module": "Módulo de Navegação",
            "UI Builder Page": "Página do UI Builder",
            "Style Sheet": "Folha de Estilo (CSS)",
            "Notification Email Script": "Script de E-mail",
            "Fix Script": "Script de Correção",
            "REST Message": "Mensagem REST",
            "Event Registry": "Registro de Evento",
            "Dictionary Entry": "Entrada de Dicionário",
            "Choice List": "Lista de Opções",
            "Form Design": "Design de Formulário",
            "Form Layout": "Layout de Formulário"
        };

        return map[type] || type;
    },

    getRecordLink: function(gr) {
        var instanceUrl = gs.getProperty('doc.uri');
        var link = "";
        var nameMatch = gr.name.match(/^(.*)_([0-9a-f]{32})$/i);
        if (nameMatch) link = instanceUrl + nameMatch[1] + ".do?sys_id=" + nameMatch[2];

        return link;
    },

    generateFromRelease: function(params) {

        var html = this.getDocumentation(params);

        var gr = new GlideRecord('u_central_documentacao_tecnica');
        gr.initialize();
        gr.u_release = params.releaseId;
        gr.u_update_set = params.updateSetId;
		gr.u_status = 'andamento';
        var usdhSysId = gr.insert();

        return {
            usdh_sys_id: usdhSysId,
            usdh_number: gr.u_number.toString()
        };
    },

    getNameUpdateSet: function() {
        // Recebe os sys_ids separados por vírgula
        var sysIds = this.getParameter('sysparm_update_set_ids');
        if (!sysIds) return '';

        var idsArray = sysIds.split(',');
        var namesArray = [];

        var gr = new GlideRecord('sys_update_set');
        gr.addQuery('sys_id', 'IN', sysIds);
        gr.query();
        while (gr.next()) {
            namesArray.push(gr.getValue('name'));
        }

        // Retorna todos os nomes separados por vírgula
        return namesArray.join(', ');
    },

});

var GetUpdateSetArtifacts = Class.create();
GetUpdateSetArtifacts.prototype = Object.extendsObject(AbstractAjaxProcessor, {

    getArtifacts: function() {
        var instanceUrl = gs.getProperty('doc.uri');

        var updates = this.getParameter('sysparm_updates') || '';
        var updatesArr = updates.split(/\s*,\s*/).map(function(u) {
            return u.trim();
        });

        var notTypes = this.getParameter('sysparm_notTypes') || '';
        var notTypesArr = notTypes.split(/\s*,\s*/).map(function(u) {
            return u.trim();
        });

        var types = this.getParameter('sysparm_types') || '';
        var typesArr = types.split(/\s*,\s*/).map(function(u) {
            return u.trim();
        });

        var application = this.getParameter('sysparm_application') || '';
        var applicationArr = application.split(/\s*,\s*/).map(function(u) {
            return u.trim();
        });

        var result = [];
        var gr = new GlideRecord('sys_update_xml');
        gr.addQuery('update_set.name', 'IN', updatesArr);
        this.getParameter('sysparm_types') ? gr.addQuery('type', 'IN', typesArr) : '';
        this.getParameter('sysparm_notTypes') ? gr.addQuery('type', 'NOT IN', notTypesArr) : '';
        this.getParameter('sysparm_application') ? gr.addQuery('application', 'IN', applicationArr) : '';
        gr.query();

        var total = gr.getRowCount();

        while (gr.next()) {
            var link = "";
            var nameMatch = gr.name.match(/^(.*)_([0-9a-f]{32})$/i);
            if (nameMatch) link = instanceUrl + nameMatch[1] + ".do?sys_id=" + nameMatch[2];

            // Verifica se já existe review salvo
            var review = new GlideRecord('u_code_review_artifact');
            var passou = false;
            var naoPassou = false;
            var comentario = '';
            if (review.get('u_link_do_artefato', link)) {
                passou = (review.u_passou_no_review == true || review.u_passou_no_review == 'true' || review.u_passou_no_review == '1');
                naoPassou = (review.u_nao_passou_no_review == true || review.u_nao_passou_no_review == 'true' || review.u_nao_passou_no_review == '1');
                comentario = review.u_comentario ? review.u_comentario.getDisplayValue() : '';
            }

            result.push({
                name: gr.target_name.toString() || "Não informado",
                link: (link !== '' ? link : "Não informado"),
                type: gr.type.toString() || "Não informado",
                updateSet: gr.update_set.name.toString() || "Não informado",
                application: gr.application.name.toString() || "Não informado",
                action: gr.action.toString() || "Não informado",
                totalCount: total.toString(),
                passou: passou,
                naoPassou: naoPassou,
                comentario: comentario
            });
        }

        return JSON.stringify(result);
    },

    saveReview: function() {

        var data = this.getParameter('sysparm_data');
        gs.info("[CodeReview] sysparm_data recebido: " + data);

        if (!data) {
            gs.error("[CodeReview] Nenhum dado recebido");
            return "Nenhum dado recebido";
        }

        try {

            var parsedData = JSON.parse(data);

            if (!parsedData || parsedData.length === 0)
                return "Lista vazia";

            var updateSet = parsedData[0].updateSet;

            var codeReviewSysId = this.getCodeReviewByUpdateSet(updateSet);

            parsedData.forEach(function(item, index) {

                if (!item.link)
                    return;

                var gr = new GlideRecord('u_code_review_artifact');
                gr.addQuery('u_nome_do_update_set', item.updateSet);
                gr.addQuery('u_link_do_artefato', item.link);
                gr.query();

				gs.log(gr.getEncodedQuery());

                // ========================
                // UPDATE
                // ========================
                if (gr.next()) {

                    gr.u_code_review = codeReviewSysId;
                    gr.u_nome_do_artefato_target_name = item.name;
                    gr.u_action_do_artefato = item.action;
                    gr.u_tipo_de_artefato = item.type;
                    gr.u_nome_do_update_set = item.updateSet;
                    gr.u_nome_da_aplicacao = item.application;
                    gr.u_passou_no_review = item.passou;
                    gr.u_nao_passou_no_review = item.naoPassou;
                    gr.u_comentario = item.comentario;

                    gr.update();

                }
                // ========================
                // INSERT
                // ========================
                else {

                    gr.initialize();

                    gr.u_code_review = codeReviewSysId;
                    gr.u_link_do_artefato = item.link;
                    gr.u_nome_do_artefato_target_name = item.name;
                    gr.u_action_do_artefato = item.action;
                    gr.u_tipo_de_artefato = item.type;
                    gr.u_nome_do_update_set = item.updateSet;
                    gr.u_nome_da_aplicacao = item.application;
                    gr.u_passou_no_review = item.passou;
                    gr.u_nao_passou_no_review = item.naoPassou;
                    gr.u_comentario = item.comentario;

                    gr.insert();
                }

            });

            return "Reviews salvos/atualizados com sucesso!";

        } catch (e) {

            gs.error("[CodeReview] Erro: " + e.message);
            return "Erro ao salvar: " + e.message;
        }
    },

    getCodeReviewByUpdateSet: function(updateSet) {

        var updateSetSysId = this.convertNamexSysIdUpdateSet(updateSet);

        if (!updateSetSysId) {
            gs.warn('[CodeReview] Update Set não encontrado: ' + updateSet);
            return '';
        }

        var cr = new GlideRecord('u_code_review');
        cr.addQuery('u_update_set', updateSetSysId);
        cr.query();

        if (cr.next()) {
            gs.info('[CodeReview] Code Review encontrado: ' + cr.getUniqueValue());
            return cr.getUniqueValue();
        }

        gs.warn('[CodeReview] Nenhum Code Review encontrado para Update Set: ' + updateSetSysId);
        return '';
    },

    convertNamexSysIdUpdateSet: function(name) {
        var gr = new GlideRecord('sys_update_set');
        gr.addQuery('name', name);
        gr.setLimit(1);
        gr.query();

        if (gr.next()) {
            return gr.sys_id.toString();
        }

        return '';
    },


    type: 'GetUpdateSetArtifacts'
});

var GetInstanceScanResults = Class.create();
GetInstanceScanResults.prototype = Object.extendsObject(AbstractAjaxProcessor, {

    // Busca e exibe os Instance Scans
    runScan: function() {
        var updateSetName = this.getParameter('sysparm_update_set');

        var html = "";
        html += "<div id='instanceScanHtml' style='background:#f9f9f9;border:1px solid #ddd;border-radius:8px;padding:12px 16px;margin-bottom:20px;'>";
        html += "<h3 style='margin-top:0;color:#0d47a1;'>Instance Scan</h3>";
        html += "<p style='font-size:13px;color:#555;margin-bottom:10px;'>Clique no número do Scan para ver os Findings.</p>";

        html += "<table style='width:100%;border-collapse:collapse;font-size:14px;margin-top:10px;'>";
        html += "<tr style='background:#e7e7e7;color:#333;font-weight:bold;'>";
        html += "<th style='padding:8px;border:1px solid #ccc;'>Instance Scan</th>";
        html += "<th style='padding:8px;border:1px solid #ccc;'>Status</th>";
        html += "</tr>";

        // Buscar update set
        var us = new GlideRecord('sys_update_set');
        us.addQuery('name', 'IN', updateSetName);
        us.query();
        if (!us.next()) {
            html += "<tr><td colspan='2' style='text-align:center;padding:10px;color:#555;'>Update Set não encontrado</td></tr>";
            html += "</table></div>";
            return html;
        }

        var updateSetSysId = us.getUniqueValue();

        // Buscar targets
        var targets = [];
        var target = new GlideRecord('scan_target');
        target.addQuery('record_id', updateSetSysId);
        target.query();
        while (target.next()) targets.push(target.getUniqueValue());

        if (targets.length == 0) {
            html += "<tr><td colspan='2' style='text-align:center;padding:10px;'>Nenhum target encontrado.</td></tr>";
            html += "</table></div>";
            return html;
        }

        // Buscar combos
        var combos = [];
        var combo = new GlideRecord('scan_combo');
        combo.addQuery('targets', 'IN', targets);
        combo.query();
        while (combo.next()) combos.push(combo.getUniqueValue());

        // Buscar resultados
        var scan = new GlideRecord('scan_result');
        scan.addQuery('combo', 'IN', combos);
		scan.orderByDesc("number");
        scan.query();

        while (scan.next()) {

            // verificar findings
            var finding = new GlideRecord("scan_finding");
            finding.addQuery("result", scan.getUniqueValue());
            finding.setLimit(1);
            finding.query();

            var hasFindings = finding.hasNext();
            var statusText = hasFindings ? "failed" : "complete";
            var statusColor = hasFindings ? "#F44336" : "#4CAF50";

            html += "<tr>";
            html += "<td style='padding:8px;border:1px solid #ccc;'>" +
                "<a href='javascript:void(0);' onclick=\"showFindings('" + scan.getUniqueValue() + "')\" " +
                "style='color:#0d47a1;font-weight:bold;text-decoration:none;'>" +
                scan.number +
                "</a></td>";
            html += "<td style='padding:8px;border:1px solid #ccc;font-weight:bold;color:" + statusColor + ";'>" + statusText + "</td>";
            html += "</tr>";
        }

        html += "</table>";
        html += "<div id='findingDetails'></div>"; // container da tabela de findings
        html += "</div>";

        return html;
    },

	// Busca e exibe os Findings
    getFindings: function() {

        var scanId = this.getParameter("sysparm_scan_id");

        var html = "";
        html += "<div style='margin-top:20px;background:#ffffff;border:1px solid #ddd;border-radius:8px;padding:12px;'>"
        html += "<h3 style='color:#0d47a1;margin-top:0;'>Findings</h3>";

        var f = new GlideRecord("scan_finding");
        f.addQuery("result", scanId);
        f.query();

        if (!f.hasNext()) {
            html += "<p style='color:#555;font-size:13px;'>Nenhum finding encontrado para este scan.</p>";
            html += "</div>";
            return html;
        }

        // =============================
        // CONTAGEM DE FINDINGS
        // =============================
        var total = 0;
        while (f.next()) total++;
        f.reset();
        f.query();

        html += `<p style='margin-top:-5px;font-size:13px;color:#444;'>${total} findings encontrados</p>`;

        html += "<table style='width:100%;border-collapse:collapse;font-size:14px;margin-top:10px;'>"
        html += "<tr style='background:#e7e7e7;font-weight:bold;'>";
        html += "<th style='padding:8px;border:1px solid #ccc;'>Severidade</th>";
        html += "<th style='padding:8px;border:1px solid #ccc;'>Check</th>";
        html += "<th style='padding:8px;border:1px solid #ccc;'>Fonte</th>";
        html += "<th style='padding:8px;border:1px solid #ccc;'>Detalhes</th>";
        html += "<th style='padding:8px;border:1px solid #ccc;'>Abrir</th>";
        html += "</tr>";

        while (f.next()) {

            // =============================
            // MAPEAR PRIORIDADE (1–4)
            // =============================
            var p = (f.check.priority + "") || "";
            var severity = "Undefined";
            var color = "#777";

            switch (p) {
                case "1":
                    severity = "Critical";
                    color = "#b71c1c"; // vermelho forte
                    break;
                case "2":
                    severity = "High";
                    color = "#e53935"; // vermelho
                    break;
                case "3":
                    severity = "Moderate";
                    color = "#fb8c00"; // laranja
                    break;
                case "4":
                    severity = "Low";
                    color = "#43a047"; // verde
                    break;
            }

            var details = f.finding_details || "—";

            html += "<tr>";

            // =======================================
            // SEVERIDADE COLORIDA
            // =======================================
            html += `
            <td style="padding:8px;border:1px solid #ccc;font-weight:bold;color:${color};">
                ${severity}
            </td>
        `;

            // =======================================
            // CHECK + DESCRIÇÃO
            // =======================================
            html += `
            <td style="padding:8px;border:1px solid #ccc;">
                <b>${f.check.getDisplayValue()}</b><br>
                <small style="color:#666;">${f.check.description || ""}</small>
            </td>
        `;

            // =======================================
            // FONTE
            // =======================================
            html += `
            <td style="padding:8px;border:1px solid #ccc;">
                ${f.source.getDisplayValue()}
            </td>
        `;

            // =======================================
            // DETALHES (EXPAND / CONTRAIR)
            // =======================================
            html += `
            <td style="padding:8px;border:1px solid #ccc;">
                <details>
                    <summary style="cursor:pointer;color:#0d47a1;">Ver detalhes</summary>
                    <div style="margin-top:5px;color:#444;">
                        <pre style="white-space:pre-wrap;">${details}</pre>
                    </div>
                </details>
            </td>
        `;

            // =======================================
            // LINK PARA REGISTRO REAL
            // =======================================
            html += `
            <td style="padding:8px;border:1px solid #ccc;text-align:center;">
                <a href="/nav_to.do?uri=scan_finding.do?sys_id=${f.getUniqueValue()}"
                   target="_blank"
                   style="color:#673ab7;font-weight:bold;text-decoration:none;">
                   Abrir
                </a>
            </td>
        `;

            html += "</tr>";
        }

        html += "</table></div>";
        return html;
    },

    type: "GetInstanceScanResults"
});
